fn quicksort<T: Ord + Clone>(arr: &mut [T], mut l: usize, mut h: usize) {
    while l < h {
        if h - l < 24 { insertion_sort(&mut arr[l..=h]); return }
        let (lt, gt) = partition_3way(arr, l, h);
        if lt - l < h - gt {
            if lt > l { quicksort(arr, l, lt - 1) }
            l = gt + 1;
        } else {
            quicksort(arr, gt + 1, h);
            if lt > l { h = lt - 1 } else { break }
        }
    }
}

fn partition_3way<T: Ord + Clone>(arr: &mut [T], l: usize, h: usize) -> (usize, usize) {
    let m = l + (h - l) / 2;
    if arr[m] < arr[l] { arr.swap(m, l) }
    if arr[h] < arr[l] { arr.swap(h, l) }
    if arr[h] < arr[m] { arr.swap(h, m) }
    let p = arr[m].clone();
    let (mut lt, mut i, mut gt) = (l, l, h);
    while i <= gt {
        match arr[i].cmp(&p) {
            Ordering::Less => { if lt < i { arr.swap(lt, i) } lt += 1; i += 1 }
            Ordering::Greater => { arr.swap(i, gt); if gt == 0 { break } gt -= 1 }
            _ => i += 1,
        }
    }
    (lt, gt)
}

